    ["DEMONHUNTERDEVOURERDUNGEONROTATION"] = "--OPENER-- \n1. Consume 2s before pull\n\n2. Reap\n\n3. Reap\n\n4. Consume until 100 Fury\n\n5. Void Ray\n\n6. Repeat until Void Metamorphosis is available\n\n7. Voidblade\n\n8. Void Metamorphosis\n\n9. Use Trinkets and Potions\n\n10. Cull\n\n11. Void Ray\n\n12. Pierce the Veil\n\n13. Collapsing Star\n\n14. Cull\n\n15. Continue with normal rotation\n\n\n-ROTATION--\n\nOutside Void Metamorphosis Priority:\n\n1. Cast Hungering Slash.\n\n2. Cast Vengeful Retreat if buffed by Voidstep.\n\n3. Cast Voidblade.\n\n4. Cast Eradicate.\n\n5. Cast Void Ray.\n\n6. Cast Reap with 4 or more Soul Fragments on the ground.\n\n7. Cast Void Metamorphosis.\n\n8. Cast Consume.\n\n\nInside Void Metamorphosis Priority:\n\n9. Cast Eradicate.\n\n10. Cast Void Ray.\n\n11. Cast Collapsing Star.\n\n12. Cast Reaper's Toll.\n\n13. Cast Vengeful Retreat if buffed by Voidstep.\n\n14. Cast Pierce the Veil.\n\n15. Cast Cull with 4 or more Soul Fragments.\n\n16. Cast Devour.",
