    ["PALADINHOLYDELVEROTATION"] = "[1] Spend Holy Power if on 5 Holy Power\n[2] Cast Divine Toll\n[3] Cast Holy Light as needed and as mana allows\n[4] Spend Infusion of Light procs on Flash of Light\n[5] Cast Holy Shock\n[6] Spend Holy Power\n[7] Cast Flash of Light, or Judgment if you need to move",
    ["PALADINHOLYRAIDROTATION"] = "[1] Spend Holy Power if on 5 Holy Power\n[2] Cast Divine Toll\n[3] Cast Holy Light as needed and as mana allows\n[4] Spend Infusion of Light procs on Flash of Light\n[5] Cast Holy Shock\n[6] Spend Holy Power\n[7] Cast Flash of Light, or Judgment if you need to move",
    ["PALADINPROTECTIONDUNGEONROTATION"] = "--OPENER-- \n[1] Consecration pre-pull as close to the boss as you can safely get without pulling.\n[2] Blessed Hammer can be used pre-pull to get a few holy power\n[3] Hand of Reckoning on pull so no DPS/Healers get punched.\n[4] Ardent Defender if you are tanking first\n[5] Avenger's Shield\n[6] Avenging Wrath\n[7] Divine Toll + Hammer of Light\n[8] Proceed normal rotation\n\n-ROTATION--\n\n[1] Cast Avenging Wrath on cooldown.\n[2] Cast Judgment on cooldown.\n[3] Cast Shield of the Righteous when you have 3-5 Holy Power or if it's free. Try not to cap Holy Power.\n[4] Cast Avenger's Shield on cooldown.\n[5] Divine Toll if you have 0 Holy Power. Try to use this on cooldown as much as possible.\n[6] Blessed Hammer / Hammer of the Righteous on cooldown.\n[7] Word of Glory if your health drops below 50% or to top yourself off if you are in danger of a big hit.\n[8] Consecration as a filler.",
    ["PALADINPROTECTIONDELVEROTATION"] = "--OPENER-- \n[1] Consecration pre-pull as close to the boss as you can safely get without pulling.\n[2] Blessed Hammer can be used pre-pull to get a few holy power\n[3] Hand of Reckoning on pull so no DPS/Healers get punched.\n[4] Ardent Defender if you are tanking first\n[5] Avenger's Shield\n[6] Avenging Wrath\n[7] Divine Toll + Hammer of Light\n[8] Proceed normal rotation\n\n-ROTATION--\n\n[1] Cast Avenging Wrath on cooldown.\n[2] Cast Judgment on cooldown.\n[3] Cast Shield of the Righteous when you have 3-5 Holy Power or if it's free. Try not to cap Holy Power.\n[4] Cast Avenger's Shield on cooldown.\n[5] Divine Toll if you have 0 Holy Power. Try to use this on cooldown as much as possible.\n[6] Blessed Hammer / Hammer of the Righteous on cooldown.\n[7] Word of Glory if your health drops below 50% or to top yourself off if you are in danger of a big hit.\n[8] Consecration as a filler.",
    ["PALADINPROTECTIONRAIDROTATION"] = "--OPENER-- \n[1] Consecration pre-pull as close to the boss as you can safely get without pulling.\n[2] Blessed Hammer can be used pre-pull to get a few holy power\n[3] Hand of Reckoning on pull so no DPS/Healers get punched.\n[4] Ardent Defender if you are tanking first\n[5] Avenger's Shield\n[6] Avenging Wrath\n[7] Divine Toll + Hammer of Light\n[8] Proceed normal rotation\n\n-ROTATION--\n\n[1] Cast Avenging Wrath on cooldown.\n[2] Cast Judgment on cooldown.\n[3] Cast Shield of the Righteous when you have 3-5 Holy Power or if it's free. Try not to cap Holy Power.\n[4] Cast Avenger's Shield on cooldown.\n[5] Divine Toll if you have 0 Holy Power. Try to use this on cooldown as much as possible.\n[6] Blessed Hammer / Hammer of the Righteous on cooldown.\n[7] Word of Glory if your health drops below 50% or to top yourself off if you are in danger of a big hit.\n[8] Consecration as a filler.",
    ["PALADINRETRIBUTIONDUNGEONROTATION"] = "--OPENER-- \n\n[1] Avenging Wrath\n[2] Light's Potential and any on-use trinkets\n[3] Execution Sentence\n[4] Wake of Ashes\n[5] Divine Toll\n[6] Hammer of Light\n[7] Continue with normal rotation.\n\n-ROTATION--\n\n[1] Cast Avenging Wrath\n[2] Cast Execution Sentence\n[3] Cast Hammer of Light\n[4] Cast Divine Storm with 5 Holy Power\n[5] Cast Wake of Ashes\n[6] Cast Divine Toll\n[7] Cast Blade of Justice with an Art of War proc\n[8] Cast Divine Storm\n[9] Cast Blade of Justice\n[10] Cast Hammer of Wrath\n[11] Cast Judgment",
    ["PALADINRETRIBUTIONDELVEROTATION"] = "--OPENER-- \n\n[1] Avenging Wrath\n[2] Light's Potential and any on-use trinkets\n[3] Execution Sentence\n[4] Wake of Ashes\n[5] Divine Toll\n[6] Hammer of Light\n[7] Continue with normal rotation.\n\n-ROTATION--\n\n[1] Cast Avenging Wrath\n[2] Cast Execution Sentence\n[3] Cast Hammer of Light\n[4] Cast Divine Storm with 5 Holy Power\n[5] Cast Wake of Ashes\n[6] Cast Divine Toll\n[7] Cast Blade of Justice with an Art of War proc\n[8] Cast Divine Storm\n[9] Cast Blade of Justice\n[10] Cast Hammer of Wrath\n[11] Cast Judgment",
    ["PALADINRETRIBUTIONRAIDAOEROTATION"] = "--OPENER-- \n\n[1] Avenging Wrath\n[2] Light's Potential and any on-use trinkets\n[3] Execution Sentence\n[4] Wake of Ashes\n[5] Divine Toll\n[6] Hammer of Light\n[7] Continue with normal rotation.\n\n-ROTATION--\n\n[1] Cast Avenging Wrath\n[2] Cast Execution Sentence\n[3] Cast Hammer of Light\n[4] Cast Divine Storm with 5 Holy Power\n[5] Cast Wake of Ashes\n[6] Cast Divine Toll\n[7] Cast Blade of Justice with an Art of War proc\n[8] Cast Divine Storm\n[9] Cast Blade of Justice\n[10] Cast Hammer of Wrath\n[11] Cast Judgment",
    ["PALADINRETRIBUTIONRAIDSTROTATION"] = "--OPENER-- \n\n[1] Avenging Wrath\n[2] Light's Potential and any on-use trinkets\n[3] Execution Sentence\n[4] Wake of Ashes\n[5] Divine Toll\n[6] Hammer of Light\n[7] Continue with normal rotation.\n\n-ROTATION--\n\n[1] Cast Avenging Wrath\n[2] Cast Execution Sentence\n[3] Cast Hammer of Light\n[4] Cast Final Verdict with 5 Holy Power\n[5] Cast Wake of Ashes\n[6] Cast Divine Toll\n[7] Cast Blade of Justice with an Art of War proc\n[8] Cast Final Verdict\n[9] Cast Blade of Justice\n[10] Cast Hammer of Wrath\n[11] Cast Judgment",
    ["ROGUEASSASSINATIONDUNGEONROTATION"] = "--OPENER-- \n[1] Cast Vanish if you did not get to stealth\n[2] Cast Garrote\n[3] Cast Garrote to extend the duration of Improved Garrote\n[4] Cast Rupture\n[5] Cast Deathmark\n[6] Cast any on-use trinkets, racials, and consumables now. This can be done via macro as well\n[7] Cast Kingsbane\n[8] Cast Crimson Tempest until either: 5 or more combo points or all targets have bleeds\n[9] Cast Fan of Knives to generate combo points if all targets already have bleeds from casting Crimson Tempest\n[10] Cast Envenom to dump combo points\n\n-ROTATION--\n\n[1] Maintain Garrote on your main target\n[2] Maintain Rupture by casting at 5 or more combo points on your main target\n[3] Cast Crimson Tempest to spread bleeds to secondary targets until you either have: 5 or more combo points or all secondary targets debuffed with Garrote and Rupture\n[4] Cast Fan of Knives until having 5 or more combo points\n[5] Cast Vanish followed by Garrote to apply Improved Garrote. In Mythic+, this is commonly held for chainpulls where you cannot stealth beforehand. Otherwise, sync with Deathmark.\n[6] Cast Deathmark on cooldown\n[7] Cast Kingsbane on cooldown, immediately after Deathmark when applicable\n[8] Cast Envenom at 5 or more combo points to avoid wasting energy and combo points",
    ["ROGUEASSASSINATIONDELVEROTATION"] = "--OPENER-- \n[1] Cast Vanish if you did not get to stealth\n[2] Cast Garrote\n[3] Cast Garrote to extend the duration of Improved Garrote\n[4] Cast Rupture\n[5] Cast Deathmark\n[6] Cast any on-use trinkets, racials, and consumables now. This can be done via macro as well\n[7] Cast Kingsbane\n[8] Cast Crimson Tempest until either: 5 or more combo points or all targets have bleeds\n[9] Cast Fan of Knives to generate combo points if all targets already have bleeds from casting Crimson Tempest\n[10] Cast Envenom to dump combo points\n\n-ROTATION--\n\n[1] Maintain Garrote on your main target\n[2] Maintain Rupture by casting at 5 or more combo points on your main target\n[3] Cast Crimson Tempest to spread bleeds to secondary targets until you either have: 5 or more combo points or all secondary targets debuffed with Garrote and Rupture\n[4] Cast Fan of Knives until having 5 or more combo points\n[5] Cast Vanish followed by Garrote to apply Improved Garrote. In Mythic+, this is commonly held for chainpulls where you cannot stealth beforehand. Otherwise, sync with Deathmark.\n[6] Cast Deathmark on cooldown\n[7] Cast Kingsbane on cooldown, immediately after Deathmark when applicable\n[8] Cast Envenom at 5 or more combo points to avoid wasting energy and combo points",
    ["ROGUEASSASSINATIONRAIDAOEROTATION"] = "--OPENER-- \n[1] Cast Vanish if you did not get to stealth\n[2] Cast Garrote\n[3] Cast Garrote to extend the duration of Improved Garrote\n[4] Cast Rupture\n[5] Cast Deathmark\n[6] Cast any on-use trinkets, racials, and consumables now. This can be done via macro as well\n[7] Cast Kingsbane\n[8] Cast Crimson Tempest until either: 5 or more combo points or all targets have bleeds\n[9] Cast Fan of Knives to generate combo points if all targets already have bleeds from casting Crimson Tempest\n[10] Cast Envenom to dump combo points\n\n-ROTATION--\n\n[1] Maintain Garrote on your main target\n[2] Maintain Rupture by casting at 5 or more combo points on your main target\n[3] Cast Crimson Tempest to spread bleeds to secondary targets until you either have: 5 or more combo points or all secondary targets debuffed with Garrote and Rupture\n[4] Cast Fan of Knives until having 5 or more combo points\n[5] Cast Vanish followed by Garrote to apply Improved Garrote. In Mythic+, this is commonly held for chainpulls where you cannot stealth beforehand. Otherwise, sync with Deathmark.\n[6] Cast Deathmark on cooldown\n[7] Cast Kingsbane on cooldown, immediately after Deathmark when applicable\n[8] Cast Envenom at 5 or more combo points to avoid wasting energy and combo points",
    ["ROGUEASSASSINATIONRAIDSTROTATION"] = "--OPENER-- \n\n[1] Cast Garrote\n[2] Cast Mutilate until 5 or more combo points\n[3] Cast Rupture\n[4] Cast Garrote to extend the duration of Improved Garrote\n[5] Cast Deathmark\n[6] Cast any on-use trinkets, racials, and consumables now. This can be done via macro as well\n[7] Cast Kingsbane\n[8] Cast Mutilate until 5 or more combo points\n[9] Cast Envenom to dump combo points\n\n-ROTATION--\n\n[1] Maintain Garrote\n[2] Cast Mutilate until having 5 or more combo points\n[3] Cast Envenom at maximum combo points when Darkest Night is active\n[4] Maintain Rupture by casting at 5 or more combo points\n[5] Cast Vanish followed by Garrote to apply Improved Garrote. This should be lined up with Deathmark in most situations\n[6] Cast Deathmark on cooldown\n[7] Cast Kingsbane on cooldown, immediately after Deathmark when applicable\n[8] Cast Envenom at 5 or more combo points, unless at 80 stacks of Implacable\n[9] Further Details",
    ["ROGUEOUTLAWDUNGEONROTATION"] = "--OPENER-- \n\n[1] Cast Adrenaline Rush\n[2] Cast Roll the Bones\n[3] Cast Keep It Rolling\n[4] Cast Dispatch\n[5] Cast Blade Rush\n[6] Build with Sinister Strike and Pistol Shot until 5 or more combo points\n[7] Cast Between the Eyes\n[8] Cast Preparation\n[9] Continue with normal rotation\n\n-ROTATION--\n\n[1] Blade Flurry if there are 2 or more targets in range, and it is not already active. If already active, recast at 4 or fewer combo points when there are 4 or more targets within range.\n[2] Cast Roll the Bones on cooldown if at stage 1 or less.\n[3] Cast Keep It Rolling if you have a stage 2 or higher Roll the Bones active.\n[4] Cast Adrenaline Rush on cooldown at 2 or fewer combo points.\n[5] Cast Blade Rush on cooldown.\n[6] Cast Between the Eyes at 6 or more combo points.\n[7] Cast Dispatch at 5 or more combo points.\n[8] Cast Pistol Shot if; Opportunity has 6 stacks OR Opportunity has 3 stacks and you are at 1-3 combo points.\n[9] Cast Sinister Strike at 5 or fewer combo points.",
    ["ROGUEOUTLAWDELVEROTATION"] = "--OPENER-- \n\n[1] Cast Adrenaline Rush\n[2] Cast Roll the Bones\n[3] Cast Keep It Rolling\n[4] Cast Dispatch\n[5] Cast Blade Rush\n[6] Build with Sinister Strike and Pistol Shot until 5 or more combo points\n[7] Cast Between the Eyes\n[8] Cast Preparation\n[9] Continue with normal rotation\n\n-ROTATION--\n\n[1] Blade Flurry if there are 2 or more targets in range, and it is not already active. If already active, recast at 4 or fewer combo points when there are 4 or more targets within range.\n[2] Cast Roll the Bones on cooldown if at stage 1 or less.\n[3] Cast Keep It Rolling if you have a stage 2 or higher Roll the Bones active.\n[4] Cast Adrenaline Rush on cooldown at 2 or fewer combo points.\n[5] Cast Blade Rush on cooldown.\n[6] Cast Between the Eyes at 6 or more combo points.\n[7] Cast Dispatch at 5 or more combo points.\n[8] Cast Pistol Shot if; Opportunity has 6 stacks OR Opportunity has 3 stacks and you are at 1-3 combo points.\n[9] Cast Sinister Strike at 5 or fewer combo points.",
    ["ROGUEOUTLAWRAIDAOEROTATION"] = "--OPENER-- \n\n[1] Cast Adrenaline Rush\n[2] Cast Roll the Bones\n[3] Cast Keep It Rolling\n[4] Cast Dispatch\n[5] Cast Blade Rush\n[6] Build with Sinister Strike and Pistol Shot until 5 or more combo points\n[7] Cast Between the Eyes\n[8] Cast Preparation\n[9] Continue with normal rotation\n\n-ROTATION--\n\n[1] Blade Flurry if there are 2 or more targets in range, and it is not already active. If already active, recast at 4 or fewer combo points when there are 4 or more targets within range.\n[2] Cast Roll the Bones on cooldown if at stage 1 or less.\n[3] Cast Keep It Rolling if you have a stage 2 or higher Roll the Bones active.\n[4] Cast Adrenaline Rush on cooldown at 2 or fewer combo points.\n[5] Cast Blade Rush on cooldown.\n[6] Cast Between the Eyes at 6 or more combo points.\n[7] Cast Dispatch at 5 or more combo points.\n[8] Cast Pistol Shot if; Opportunity has 6 stacks OR Opportunity has 3 stacks and you are at 1-3 combo points.\n[9] Cast Sinister Strike at 5 or fewer combo points.",
    ["ROGUEOUTLAWRAIDSTROTATION"] = "--OPENER-- \n\n[1] Cast Adrenaline Rush\n[2] Cast Roll the Bones\n[3] Cast Keep It Rolling\n[4] Cast Dispatch\n[5] Cast Blade Rush\n[6] Build with Sinister Strike and Pistol Shot until 5 or more combo points\n[7] Cast Between the Eyes\n[8] Cast Preparation\n[9] Continue with normal rotation\n\n-ROTATION--\n\n[1] Cast Roll the Bones on cooldown if at stage 1 or less.\n[2] Cast Keep It Rolling if you have a stage 2 or higher Roll the Bones active.\n[3] Cast Preparation whenever Between the Eyes, Adrenaline Rush, and Blade Rush are on cooldown.\n[4] Cast Adrenaline Rush on cooldown at 2 or fewer combo points.\n[5] Cast Blade Rush on cooldown.\n[6] Cast Between the Eyes at 6 or more combo points.\n[7] Cast Dispatch at 5 or more combo points.\n[8] Cast Pistol Shot if; Opportunity has 6 stacks OR Opportunity has 3 stacks and you are at 1-3 combo points.\n[9] Cast Sinister Strike at 5 or fewer combo points.",
    ["ROGUESUBTLETYDUNGEONROTATION"] = "--OPENER-- \n\n[1] Make sure to be in Stealth before pull.\n[2] Start the fight with Shadowstrike.\n[3] Cast Shadow Dance.\n[4] Cast Shadow Blades.\n[5] Use your combat potion (Tempered Potion).\n[6] Use your trinket.\n[7] Cast Secret Technique.\n[8] Repeat the following steps for the rest of Shadow Dance.\n[9] Cast Shuriken Storm.\n[10] Cast Black Powder.\n[11] Cast Eviscerate instead of Black Powder with Coup de Grace.\n[12] Continue with your normal rotation.\n\n-ROTATION--\n\n[1] Cast Shadowstrike from Stealth.\n[2] continue based on the following priority: During Shadow Dance\n[3] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[4] Cast Secret Technique.\n[5] Cast Eviscerate with Coup de Grace.\n[6] Cast Black Powder.\n[7] Use Combo Point builder with the following priority:\n[8] Cast Shadowstrike with exactly 2 targets\n[9] Cast Shuriken Storm.\n[10] Outside of Shadow Dance\n[11] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[12] Cast Eviscerate with Coup de Grace.\n[13] Cast Black Powder.\n[14] Use Combo Point builder with the following priority:\n[15] Cast Shuriken Storm.\n[16] Cooldowns\n[17] Cast Shadow Dance with 6 or more Combo Points when Secret Technique is ready or during Shadow Blades.\n[18] Cast Shadow Blades if you have Shadow Dance ready.\n[19] Cast Vanish on cooldown with low Combo Points.",
    ["ROGUESUBTLETYDELVEROTATION"] = "--OPENER-- \n\n[1] Make sure to be in Stealth before pull.\n[2] Start the fight with Shadowstrike.\n[3] Cast Shadow Dance.\n[4] Cast Shadow Blades.\n[5] Use your combat potion (Tempered Potion).\n[6] Use your trinket.\n[7] Cast Secret Technique.\n[8] Repeat the following steps for the rest of Shadow Dance.\n[9] Cast Shuriken Storm.\n[10] Cast Black Powder.\n[11] Cast Eviscerate instead of Black Powder with Coup de Grace.\n[12] Continue with your normal rotation.\n\n-ROTATION--\n\n[1] Cast Shadowstrike from Stealth.\n[2] continue based on the following priority: During Shadow Dance\n[3] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[4] Cast Secret Technique.\n[5] Cast Eviscerate with Coup de Grace.\n[6] Cast Black Powder.\n[7] Use Combo Point builder with the following priority:\n[8] Cast Shadowstrike with exactly 2 targets\n[9] Cast Shuriken Storm.\n[10] Outside of Shadow Dance\n[11] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[12] Cast Eviscerate with Coup de Grace.\n[13] Cast Black Powder.\n[14] Use Combo Point builder with the following priority:\n[15] Cast Shuriken Storm.\n[16] Cooldowns\n[17] Cast Shadow Dance with 6 or more Combo Points when Secret Technique is ready or during Shadow Blades.\n[18] Cast Shadow Blades if you have Shadow Dance ready.\n[19] Cast Vanish on cooldown with low Combo Points.",
    ["ROGUESUBTLETYRAIDAOEROTATION"] = "--OPENER-- \n\n[1] Make sure to be in Stealth before pull.\n[2] Start the fight with Shadowstrike.\n[3] Cast Shadow Dance.\n[4] Cast Shadow Blades.\n[5] Use your combat potion (Tempered Potion).\n[6] Use your trinket.\n[7] Cast Secret Technique.\n[8] Repeat the following steps for the rest of Shadow Dance.\n[9] Cast Shuriken Storm.\n[10] Cast Black Powder.\n[11] Cast Eviscerate instead of Black Powder with Coup de Grace.\n[12] Continue with your normal rotation.\n\n-ROTATION--\n\n[1] Cast Shadowstrike from Stealth.\n[2] continue based on the following priority: During Shadow Dance\n[3] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[4] Cast Secret Technique.\n[5] Cast Eviscerate with Coup de Grace.\n[6] Cast Black Powder.\n[7] Use Combo Point builder with the following priority:\n[8] Cast Shadowstrike with exactly 2 targets\n[9] Cast Shuriken Storm.\n[10] Outside of Shadow Dance\n[11] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[12] Cast Eviscerate with Coup de Grace.\n[13] Cast Black Powder.\n[14] Use Combo Point builder with the following priority:\n[15] Cast Shuriken Storm.\n[16] Cooldowns\n[17] Cast Shadow Dance with 6 or more Combo Points when Secret Technique is ready or during Shadow Blades.\n[18] Cast Shadow Blades if you have Shadow Dance ready.\n[19] Cast Vanish on cooldown with low Combo Points.",
    ["ROGUESUBTLETYRAIDSTROTATION"] = "--OPENER-- \n\n[1] Make sure to be in Stealth before pull.\n[2] Start the fight with Shadowstrike.\n[3] Cast Shadow Dance.\n[4] Cast Shadow Blades.\n[5] Use your combat potion (Tempered Potion).\n[6] Use your trinket.\n[7] Cast Secret Technique.\n[8] Repeat the following steps for the rest of Shadow Dance.\n[9] Cast Shadowstrike.\n[10] Cast Eviscerate.\n[11] Continue with your normal rotation.\n\n-ROTATION--\n\n[1] Use Shadowstrike from Stealth.\n[2] continue based on the following priority: During Shadow Dance\n[3] Use Finishing Moves when on 6 or more Combo Points with the following priority:\n[4] Cast Secret Technique.\n[5] Cast Eviscerate.\n[6] Cast Combo Point builder with the following priority:\n[7] Cast Shadowstrike.\n[8] Outside of Shadow Dance\n[9] Cast Finishing Moves when on 6 or more Combo Points with the following priority:\n[10] Cast Eviscerate.\n[11] Cast Combo Point builder with the following priority:\n[12] Cast Backstab.\n[13] Cooldowns\n[14] Use Shadow Dance with 6 or more Combo Points when Secret Technique is ready or during Shadow Blades.\n[15] Use Shadow Blades if you have Shadow Dance ready.\n[16] Use Vanish on cooldown with low Combo Points.",
    ["SHAMANELEMENTALDUNGEONROTATION"] = "--OPENER-- \n[1] Stormkeeper\n[2] Lava Burst\n[3] Ascendance\n[4] Tempest\n[5] Lava Burst\n[6] Lightning Bolt\n[7] Continue with normal priority\n\n-ROTATION--\n\n[1] Remember to use Spiritwalker's Grace and Nature's Swiftness for movement events.\n[2] Cast Stormkeeper on cooldown.\n[3] Cast Ascendance roughly on cooldown, but always after Stormkeeper\n[4] Cast Earthquake against 4 or more targets if possible.\n[5] Cast Elemental Blast against 3 or less targets if possible.\n[6] Cast Voltaic Blaze to refresh Flame Shock.\n[7] Cast Chain Lightning / Tempest as your filler.",
    ["SHAMANELEMENTALRAIDAOEROTATION"] = "--OPENER-- \n[1] Stormkeeper\n[2] Lava Burst\n[3] Ascendance\n[4] Tempest\n[5] Lava Burst\n[6] Lightning Bolt\n[7] Continue with normal priority\n\n-ROTATION--\n\n[1] Remember to use Spiritwalker's Grace and Nature's Swiftness for movement events.\n[2] Cast Stormkeeper on cooldown.\n[3] Cast Ascendance roughly on cooldown, but always after Stormkeeper\n[4] Cast Earthquake against 4 or more targets if possible.\n[5] Cast Elemental Blast against 3 or less targets if possible.\n[6] Cast Voltaic Blaze to refresh Flame Shock.\n[7] Cast Chain Lightning / Tempest as your filler.",
    ["SHAMANELEMENTALDELVEROTATION"] = "--OPENER-- \n[1] Stormkeeper\n[2] Lava Burst\n[3] Ascendance\n[4] Tempest\n[5] Lava Burst\n[6] Lightning Bolt\n[7] Continue with normal priority\n\n-ROTATION--\n\n[1] Remember to use Spiritwalker's Grace and Nature's Swiftness for movement events.\n[2] Cast Stormkeeper on cooldown.\n[3] Cast Ascendance roughly on cooldown, but always after Stormkeeper\n[4] Cast Earthquake against 4 or more targets if possible.\n[5] Cast Elemental Blast against 3 or less targets if possible.\n[6] Cast Voltaic Blaze to refresh Flame Shock.\n[7] Cast Chain Lightning / Tempest as your filler.",
    ["SHAMANELEMENTALRAIDSTROTATION"] = "--OPENER-- \n[1] Stormkeeper\n[2] Lava Burst\n[3] Ascendance\n[4] Tempest\n[5] Lava Burst\n[6] Lightning Bolt\n[7] Continue with normal priority\n\n-ROTATION--\n\n[1] Remember to use Spiritwalker's Grace and Nature's Swiftness for movement events.\n[2] Cast Stormkeeper on cooldown.\n[3] Cast Ascendance roughly on cooldown, but always after Stormkeeper\n[4] Refresh Flame Shock with Voltaic Blaze within the pandemic window (30% of its current maximum duration) if you do not have Master of the Elements active.\n[5] Cast Lava Burst if you do not have Master of the Elements active and will not overcap\n[6] Cast Tempest to consume Master of the Elements.\n[7] Cast Lightning Bolt buffed by Stormkeeper to consume Master of the Elements.\n[8] Cast Elemental Blast.\n[9] Cast Lightning Bolt / Tempest as your filler.",
    ["SHAMANENHANCEMENTDUNGEONROTATION"] = "--OPENER-- \n\n[1] Cast Voltaic Blaze on the way into melee\n[2] Cast Surging Totem\n[3] Cast Sundering\n[4] Cast Doom Winds and immediately Crash Lightning\n[5] Cast Lava Lash to trigger Hot Hand\n[6] Cast Primordial Storm with 10 Maelstrom Weapon\n[7] Cast Lava Lash\n[8] Continue with normal ability priority\n\n-ROTATION-\n\n[1] Cast Voltaic Blaze if Flame Shock isn't currently active.\n[2] Cast Surging Totem.\n[3] Cast Sundering.\n[4] Cast Lava Lash with Hot Hand or Whirling Fire active.\n[5] Cast Doom Winds.\n[6] Cast Primordial Storm with 10 Maelstrom Weapon stacks.\n[7] Cast Crash Lightning.\n[8] Cast Stormstrike during Doom Winds.\n[9] Cast Voltaic Blaze.\n[10] Cast Chain Lightning with 10 Maelstrom Weapon stacks.\n[11] Cast Lava Lash.\n[12] Cast Stormstrike.\n[13] Cast Chain Lightning with 5+ Maelstrom Weapon stacks.",
