local function Smash(str)
    if not str then return "" end
    local s = str:upper():gsub("M%+", "DUNGEON")
    return s:gsub("[^A-Z0-9]", "")
end

local function InjectIntoBlizzard(talentString, specName, scenario)
    local dialog = ClassTalentLoadoutImportDialog
    if not dialog then return false end
    dialog:ShowDialog()
    local importBox = dialog.ImportControl and dialog.ImportControl.InputContainer and dialog.ImportControl.InputContainer.EditBox
    local nameBox = dialog.NameControl and dialog.NameControl.EditBox
    if importBox and nameBox then
        importBox:SetText(talentString)
        nameBox:SetText("QB_" .. specName:gsub("%s+", "") .. "_" .. scenario)
        return true
    end
    return false
end

local function ImportBuild(talentString, specName, scenario)
    if not talentString or talentString == "" then return end
    if InCombatLockdown() then Print("Error: In Combat!") return end
    if not PlayerSpellsFrame then UIParentLoadAddOn("Blizzard_PlayerSpells") end
    if not InjectIntoBlizzard(talentString, specName, scenario) then
        Print("Error: Open Talents (N) first.")
    end
end

