-- SCENARIO SELECTION POPUP
local function CreateScenarioPopup(isRotation)
    if QB_ScenarioPopup then 
        local specIdx = GetSpecialization()
        if specIdx then
            local role = GetSpecializationRole(specIdx)
            if role == "DAMAGER" then
                QB_ScenarioPopup.st:Show()
                QB_ScenarioPopup.aoe:Show()
                QB_ScenarioPopup.gen:Hide()
                QB_ScenarioPopup.delve:SetPoint("TOP", 0, -125)
                QB_ScenarioPopup:SetSize(170, 200)
            else
                QB_ScenarioPopup.st:Hide()
                QB_ScenarioPopup.aoe:Hide()
                QB_ScenarioPopup.gen:Show()
                QB_ScenarioPopup.delve:SetPoint("TOP", 0, -100)
                QB_ScenarioPopup:SetSize(170, 175)
            end
        end
        QB_ScenarioPopup.isRotation = isRotation
        return QB_ScenarioPopup 
    end
    
    local f = CreateFrame("Frame", "QB_ScenarioPopup", UIParent, "BackdropTemplate")
    f:SetSize(170, 200)
    f:SetPoint("CENTER", 0, 0)
    f:SetFrameStrata("DIALOG")
    f:SetBackdrop({
        bgFile = "Interface\\DialogFrame\\UI-DialogBox-Background",
        edgeFile = "Interface\\DialogFrame\\UI-DialogBox-Gold-Border",
        tile = true, tileSize = 32, edgeSize = 32,
        insets = { left = 11, right = 12, top = 12, bottom = 11 }
    })
    
    local close = CreateFrame("Button", nil, f, "UIPanelCloseButton")
    close:SetPoint("TOPRIGHT", -5, -5)
    close:SetScript("OnClick", function() f:Hide() end)
    
    local title = f:CreateFontString(nil, "OVERLAY", "GameFontNormal")
    title:SetPoint("TOP", 0, -15)
    title:SetText("SELECT MODE")

    local function CreateBtn(text, scenarioKey, y)
        local b = CreateFrame("Button", nil, f, "UIPanelButtonTemplate")
        b:SetSize(140, 25)
        b:SetText(text)
        b:SetPoint("TOP", 0, y)
        b:SetScript("OnClick", function()
            local function ProcessSelection(source)
                local specIdx = GetSpecialization()
                local _, specName = GetSpecializationInfo(specIdx)
                local _, classFile = UnitClass("player")
                
                local key = Smash(classFile) .. Smash(specName) .. scenarioKey
                if f.isRotation then
                    key = key .. "ROTATION"
                else
                    key = key .. source
                end
                
                local str = (QuickBuildsDB and QuickBuildsDB[key]) or BAKED_DATA[key]
                
                if str then 
                    if f.isRotation then
                        ShowRotationWindow(str, text .. " Rotation")
                    else
                        ImportBuild(str, specName, scenarioKey .. "_" .. source) 
                    end
                else 
                    if f.isRotation then
                         Print("No rotation found for " .. text .. " (Key: " .. key .. ")")
                    else
                         Print("No build found for " .. text .. " (" .. source .. ")") 
                    end
                end
                f:Hide()
            end

            if f.isRotation then
                -- Skip source selection for rotation
                ProcessSelection("")
            else
                local popup = CreateSourcePopup(b, ProcessSelection)
                popup:Show()
            end
        end)
        return b
    end

    f.dungeon = CreateBtn("M+ / Dungeon", "DUNGEON", -45)
    f.st = CreateBtn("Raid ST", "RAIDST", -70)
    f.aoe = CreateBtn("Raid Cleave", "RAIDAOE", -95)
    f.gen = CreateBtn("Raid General", "RAID", -70)
    f.delve = CreateBtn("Delve", "DELVE", -125)

    -- Initial Setup
    local specIdx = GetSpecialization()
    if specIdx then
        local role = GetSpecializationRole(specIdx)
        if role == "DAMAGER" then
            f.st:Show()
            f.aoe:Show()
            f.gen:Hide()
            f.delve:SetPoint("TOP", 0, -125)
            f:SetSize(170, 200)
        else
            f.st:Hide()
            f.aoe:Hide()
            f.gen:Show()
            f.delve:SetPoint("TOP", 0, -100)
            f:SetSize(170, 175)
        end
    end

    f.isRotation = isRotation
    f:Hide()
    return f
end

