-- MINIMAP BUTTON
local function CreateMinimapButton()
    local b = CreateFrame("Button", "QB_MinimapButton", Minimap)
    b:SetSize(32, 32)
    b:SetFrameStrata("MEDIUM")
    b:SetFrameLevel(8)
    b:SetPoint("CENTER", -12, -80) -- Default position
    b:SetMovable(true)
    b:EnableMouse(true)
    b:RegisterForDrag("LeftButton")
    
    -- Icon Texture
    local icon = b:CreateTexture(nil, "BACKGROUND")
    icon:SetTexture("Interface\\Icons\\INV_Misc_Book_09")
    icon:SetSize(20, 20)
    icon:SetPoint("CENTER")
    
    -- Circular Mask
    local mask = b:CreateMaskTexture()
    mask:SetTexture("Interface\\CharacterFrame\\TempPortraitAlphaMask")
    mask:SetSize(20, 20)
    mask:SetPoint("CENTER")
    icon:AddMaskTexture(mask)
    
    -- Border
    local border = b:CreateTexture(nil, "OVERLAY")
    border:SetTexture("Interface\\Minimap\\MiniMap-TrackingBorder")
    border:SetSize(54, 54)
    border:SetPoint("TOPLEFT", 0, 0)
    
    b:SetHighlightTexture("Interface\\Minimap\\UI-Minimap-ZoomButton-Highlight")
    
    b:SetScript("OnDragStart", function(self)
        self:SetScript("OnUpdate", function(self)
            local x, y = GetCursorPosition()
            local scale = Minimap:GetEffectiveScale()
            local cx, cy = Minimap:GetCenter()
            x, y = x / scale - cx, y / scale - cy
            local dist = math.sqrt(x*x + y*y)
            -- Dynamic radius based on Minimap size, ensuring it's outside
            local radius = (Minimap:GetWidth() / 2) + 10 
            local angle = math.atan2(y, x)
            self:SetPoint("CENTER", math.cos(angle)*radius, math.sin(angle)*radius)
        end)
    end)
    
    b:SetScript("OnDragStop", function(self)
        self:SetScript("OnUpdate", nil)
    end)
    
    b:SetScript("OnClick", ToggleDashboard)
    
    b:SetScript("OnEnter", function(self)
        GameTooltip:SetOwner(self, "ANCHOR_LEFT")
        GameTooltip:SetText("QuickBuilds Companion")
        GameTooltip:AddLine("Left-Click to open dashboard", 1, 1, 1)
        GameTooltip:Show()
    end)
    
    b:SetScript("OnLeave", function() GameTooltip:Hide() end)
end

