    top:SetColorTexture(unpack(borderColor))
    top:SetPoint("TOPLEFT")
    top:SetPoint("TOPRIGHT")
    top:SetHeight(1)
    
    local bottom = f:CreateTexture(nil, "BORDER")
    bottom:SetColorTexture(unpack(borderColor))
    bottom:SetPoint("BOTTOMLEFT")
    bottom:SetPoint("BOTTOMRIGHT")
    bottom:SetHeight(1)
    
    local left = f:CreateTexture(nil, "BORDER")
    left:SetColorTexture(unpack(borderColor))
    left:SetPoint("TOPLEFT")
    left:SetPoint("BOTTOMLEFT")
    left:SetWidth(1)
    
    local right = f:CreateTexture(nil, "BORDER")
