        local specIdx = GetSpecialization()
        if not specIdx then f:Hide() return end
        
        local _, specName = GetSpecializationInfo(specIdx)
        local _, classFile = UnitClass("player")
        local key = Smash(classFile) .. Smash(specName)
        local priority = STAT_PRIORITIES[key]
        
        if priority then
            f.text:SetText("Stat Prio: " .. priority)
            f:SetWidth(f.text:GetStringWidth() + 24)
            f:Show()
        else
            f:Hide()
        end
    end
    
    f:RegisterEvent("PLAYER_SPECIALIZATION_CHANGED")
    f:RegisterEvent("PLAYER_ENTERING_WORLD")
    f:SetScript("OnEvent", Update)
    
    CharacterFrame:HookScript("OnShow", Update)
end

